import React, { useCallback, useMemo, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiCheck, FiClock, FiTrendingUp, FiX, FiTrash2 } from 'react-icons/fi';
import { bookingApi } from '../../api/bookingApi';
import BookingStatusBadge from './BookingStatusBadge';
import Modal from '../../components/common/Modal';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';

const BookingApproval = () => {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [allBookings, setAllBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('PENDING');
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [reason, setReason] = useState('');
  const [action, setAction] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [error, setError] = useState(null);

  const getErrorText = (err, fallback) => {
    if (!err) return fallback;
    if (typeof err === 'string') return err;
    if (typeof err === 'object') {
      if (typeof err.message === 'string' && err.message.trim()) return err.message;
      if (typeof err.error === 'string' && err.error.trim()) return err.error;
    }
    return fallback;
  };

  useEffect(() => {
    loadBookingsByStatus(activeTab);
  }, [activeTab]);

  const reloadMetrics = useCallback(async () => {
    try {
      const data = await bookingApi.getAllBookings({});
      setAllBookings(data || []);
    } catch {
      setAllBookings([]);
    }
  }, []);

  useEffect(() => {
    reloadMetrics();
  }, [reloadMetrics]);

  const loadBookingsByStatus = async (tab) => {
    try {
      setLoading(true);
      const data = await bookingApi.getAllBookings({ status: tab });
      setBookings(data);
      setError(null);
    } catch (err) {
      setError(getErrorText(err, 'Failed to load bookings'));
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = (booking) => {
    setSelectedBooking(booking);
    setAction('approve');
    setShowModal(true);
  };

  const handleReject = (booking) => {
    setSelectedBooking(booking);
    setAction('reject');
    setShowModal(true);
  };

  const handleSubmit = async () => {
    try {
      if (action === 'approve') {
        await bookingApi.approveBooking(selectedBooking.id, reason);
      } else {
        await bookingApi.rejectBooking(selectedBooking.id, reason);
      }
      setShowModal(false);
      setReason('');
      reloadMetrics();
      loadBookingsByStatus(activeTab);
    } catch (err) {
      setError(getErrorText(err, 'Failed to process booking action'));
    }
  };

  const handleDelete = (booking) => {
    setDeleteTarget(booking);
    setShowDeleteModal(true);
  };

  const handleConfirmDelete = async () => {
    try {
      if (!deleteTarget) return;
      await bookingApi.deleteBooking(deleteTarget.id);
      setShowDeleteModal(false);
      setDeleteTarget(null);
      setError(null);
      reloadMetrics();
      loadBookingsByStatus(activeTab);
    } catch (err) {
      setError(getErrorText(err, 'Failed to delete booking request'));
    }
  };

  const handleDetails = (booking) => {
    navigate(`/bookings/${booking.id}`, { state: { booking } });
  };

  const pendingCount = useMemo(
    () => (allBookings || []).filter((b) => b.status === 'PENDING').length,
    [allBookings]
  );

  const avgDurationHours = useMemo(() => {
    const base = (allBookings || []).filter((b) => b.status === 'PENDING');
    if (base.length === 0) return null;
    const totalMs = base.reduce((sum, b) => {
      const start = new Date(b.startTime).getTime();
      const end = new Date(b.endTime).getTime();
      if (!Number.isFinite(start) || !Number.isFinite(end) || end <= start) return sum;
      return sum + (end - start);
    }, 0);
    if (totalMs <= 0) return null;
    return totalMs / base.length / 36e5;
  }, [allBookings]);

  const utilizationPercent = useMemo(() => {
    const total = (allBookings || []).length;
    if (total === 0) return 0;
    const approved = (allBookings || []).filter((b) => b.status === 'APPROVED').length;
    return Math.round((approved / total) * 100);
  }, [allBookings]);

  const formatDate = (dateString) =>
    new Date(dateString).toLocaleDateString(undefined, {
      month: 'short',
      day: '2-digit',
      year: 'numeric',
    });

  const formatTime = (dateString) =>
    new Date(dateString).toLocaleTimeString(undefined, {
      hour: '2-digit',
      minute: '2-digit',
    });

  if (loading) return <LoadingSpinner />;

  return (
    <div className="booking-approval-page">
      <div className="booking-page-header">
        <div>
          <h1>Request Management</h1>
          <p>Oversee and manage space allocation requests across the campus ecosystem.</p>
        </div>
      </div>

      <div className="request-metrics">
        <div className="metric-card">
          <div className="metric-label">New Requests</div>
          <div className="metric-value">{pendingCount}</div>
          <div className="metric-sub">
            <FiTrendingUp aria-hidden="true" /> Updated
          </div>
        </div>

        <div className="metric-card">
          <div className="metric-label">Avg. Response Time</div>
          <div className="metric-value">{avgDurationHours == null ? '—' : `${avgDurationHours.toFixed(1)}h`}</div>
          <div className="metric-sub">Based on request duration</div>
        </div>

        <div className="metric-card metric-card-wide">
          <div className="metric-label">Capacity Overview</div>
          <div className="metric-wide-title">Campus Utilization is at {utilizationPercent}%</div>
          <div className="metric-bar" aria-hidden="true">
            <span style={{ width: `${utilizationPercent}%` }} />
          </div>
        </div>
      </div>

      <div className="booking-tabs booking-tabs-grid" role="tablist" aria-label="Bookings">
        <button
          type="button"
          role="tab"
          aria-selected={activeTab === 'PENDING'}
          className={`booking-tab ${activeTab === 'PENDING' ? 'active' : ''}`}
          onClick={() => setActiveTab('PENDING')}
        >
          Pending
        </button>
        <button
          type="button"
          role="tab"
          aria-selected={activeTab === 'APPROVED'}
          className={`booking-tab ${activeTab === 'APPROVED' ? 'active' : ''}`}
          onClick={() => setActiveTab('APPROVED')}
        >
          Approved
        </button>
        <button
          type="button"
          role="tab"
          aria-selected={activeTab === 'REJECTED'}
          className={`booking-tab ${activeTab === 'REJECTED' ? 'active' : ''}`}
          onClick={() => setActiveTab('REJECTED')}
        >
          Rejected
        </button>
      </div>

      {error && <ErrorAlert message={error} />}

      {bookings.length === 0 ? (
        <p className="no-data">No bookings found.</p>
      ) : (
        <>
          <div className="queue-header">
            <div className="queue-title">
              Current Queue <span className="queue-pill">{activeTab === 'PENDING' ? 'Active' : activeTab.toLowerCase()}</span>
            </div>
            <div className="queue-sort">Newest First</div>
          </div>

          <div className="queue-list">
            {bookings.map((booking) => (
              <article key={booking.id} className="queue-row">
                <div className="queue-card-header">
                  <div className="queue-user">
                    <div className="queue-avatar" aria-hidden="true">
                      {(booking.userName || 'U').slice(0, 1).toUpperCase()}
                    </div>
                    <div className="queue-user-meta">
                      <p className="queue-user-name">{booking.userName || 'Campus User'}</p>
                      <small className="queue-user-role">Requested by</small>
                    </div>
                  </div>

                  {activeTab !== 'PENDING' ? (
                    <div className="queue-status">
                      <BookingStatusBadge status={booking.status} />
                    </div>
                  ) : null}
                </div>

                <div className="queue-details">
                  <div className="queue-details-card">
                    <div>
                      <p className="queue-label">Time & Location</p>
                      <p className="queue-line">
                        <FiClock /> {formatDate(booking.startTime)} · {formatTime(booking.startTime)} - {formatTime(booking.endTime)}
                      </p>
                      <small className="queue-muted">{booking.resourceName}</small>
                    </div>

                    <div>
                      <p className="queue-label">Purpose</p>
                      <p className="queue-muted">{booking.purpose || 'No purpose provided.'}</p>
                    </div>
                  </div>
                </div>

                <div className="queue-card-footer">
                  <button
                    className="action-pill action-pill-detail"
                    type="button"
                    onClick={() => handleDetails(booking)}
                    aria-label="Details"
                    title={`Request #REQ-${2000 + booking.id}`}
                  >
                    Detail
                  </button>

                  <div className="queue-footer-right">
                    {activeTab === 'PENDING' ? (
                      <>
                        <button
                          type="button"
                          className="action-pill action-pill-approve"
                          onClick={() => handleApprove(booking)}
                        >
                          <FiCheck /> Accept
                        </button>
                        <button
                          type="button"
                          className="action-pill action-pill-reject"
                          onClick={() => handleReject(booking)}
                        >
                          <FiX /> Reject
                        </button>
                      </>
                    ) : (activeTab === 'APPROVED' || activeTab === 'REJECTED') &&
                      (booking.status === 'APPROVED' || booking.status === 'REJECTED') ? (
                      <button
                        type="button"
                        className="action-pill action-pill-delete"
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDelete(booking);
                        }}
                      >
                        <FiTrash2 /> Delete
                      </button>
                    ) : null}
                  </div>
                </div>
              </article>
            ))}
          </div>
        </>
      )}

      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={action === 'approve' ? 'Approve Booking' : 'Reject Booking'}
      >
        <div className="modal-form">
          <p>
            Are you sure you want to {action} this booking for <strong>{selectedBooking?.resourceName}</strong>?
          </p>
          <div className="form-group">
            <label>Reason:</label>
            <textarea
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder={action === 'approve' ? 'Optional reason for approval...' : 'Required reason for rejection...'}
              rows="3"
            />
          </div>
          <div className="modal-actions">
            <button className="btn-cancel" onClick={() => setShowModal(false)}>
              Cancel
            </button>
            <button 
              className={action === 'approve' ? 'btn-approve' : 'btn-reject'}
              onClick={handleSubmit}
            >
              Confirm {action === 'approve' ? 'Approve' : 'Reject'}
            </button>
          </div>
        </div>
      </Modal>

      <Modal
        isOpen={showDeleteModal}
        onClose={() => setShowDeleteModal(false)}
        title="Delete Request"
      >
        <div className="modal-form">
          <p>
            Delete request for <strong>{deleteTarget?.resourceName}</strong>? This action cannot be undone.
          </p>
          <div className="modal-actions">
            <button className="btn-cancel" onClick={() => setShowDeleteModal(false)}>
              Cancel
            </button>
            <button className="btn-reject" onClick={handleConfirmDelete}>
              Delete
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default BookingApproval;
